+/// Split a command on && only (simpler than split_multi_command).
+/// Returns None if no && found.
+fn split_and_chain(cmd: &str) -> Option<Vec<&str>> {
+    if !cmd.contains("&&") {
+        return None;
+    }
+
+    let mut segments = Vec::new();
+    let mut current_start = 0;
+    let mut in_single = false;
+    let mut in_double = false;
+    let mut escaped = false;
+    let bytes = cmd.as_bytes();
+    let mut i = 0;
+
+    while i < bytes.len() {
+        let b = bytes[i];
+
+        if escaped {
+            escaped = false;
+            i += 1;
+            continue;
+        }
+
+        if b == b'\\' {
+            escaped = true;
+            i += 1;
+            continue;
+        }
+
+        if b == b'\'' && !in_double {
+            in_single = !in_single;
+        } else if b == b'"' && !in_single {
+            in_double = !in_double;
+        } else if !in_single && !in_double && b == b'&' && i + 1 < bytes.len() && bytes[i + 1] == b'&' {
+            let segment = &cmd[current_start..i];
+            let trimmed = segment.trim();
+            if !trimmed.is_empty() {
+                segments.push(trimmed);
+            }
+            current_start = i + 2;
+            i += 1; // Skip second '&'
+        }
+
+        i += 1;
+    }
+
+    // Add final segment
+    let final_segment = &cmd[current_start..];
+    let trimmed = final_segment.trim();
+    if !trimmed.is_empty() {
+        segments.push(trimmed);
+    }
+
+    if segments.len() > 1 {
+        Some(segments)
+    } else {
+        None
+    }
+}
