+/// The wrapper script that chains RCH and DCG hooks.
+/// RCH handles compilation commands (returns updatedInput with rch exec).
+/// DCG handles destructive command blocking.
+/// If RCH modifies the command, use that; otherwise defer to DCG.
+const RCH_DCG_WRAPPER_SCRIPT: &str = r#"#!/bin/bash
+# RCH-DCG Chain - Auto-generated by rch hook install
+# Chains RCH (compilation) and DCG (safety) hooks for Claude Code.
+# Claude Code runs hooks in parallel, so we need this wrapper to chain them properly.
+
+# Read stdin once and store it
+input=$(cat)
+
+# Run RCH first
+rch_output=$(echo "$input" | "__RCH_PATH__" 2>/dev/null)
+
+# If RCH returned JSON with updatedInput, use that (compilation intercepted)
+if echo "$rch_output" | grep -q '"updatedInput"'; then
+    echo "$rch_output"
+    exit 0
+fi
+
+# Otherwise, run DCG on the original input (safety check)
+echo "$input" | dcg 2>/dev/null
+"#;
