+    let style = ctx.theme();
+
+    // Check if DCG is available
+    let dcg_available = which::which("dcg").is_ok();
+
+    if !dcg_available {
+        // No DCG - just use rch directly
+        if !ctx.is_json() {
+            println!(
+                "  {} DCG not detected, using RCH directly",
+                StatusIndicator::Info.display(style)
+            );
+        }
+        return Ok((rch_path.to_string(), false));
+    }
+
+    // DCG is available - create wrapper script
+    if !ctx.is_json() {
+        println!(
+            "  {} DCG detected, creating RCH-DCG wrapper script",
+            StatusIndicator::Info.display(style)
